class TickerSection extends HTMLElement{constructor(){super(),window.addEventListener("load",(()=>{this.update()})),window.addEventListener("resize",(()=>{this.querySelectorAll(".ticker__content--clone").forEach((t=>t.remove())),this.update()}))}connectedCallback(){this.content=this.querySelector(".ticker__content"),this.speed=parseInt(this.dataset.speed),this.classList.remove("hidden"),this.update()}update(){this.classList.remove("animate"),this.getSizes(),setTimeout((()=>{this.cloning(),this.setSpeed(),this.classList.add("animate")}),100)}getSizes(){this.width=this.clientWidth,this.contentWidth=0,this.content.childNodes.forEach((t=>{this.contentWidth=this.contentWidth+t.clientWidth}))}setSpeed(){this.style.setProperty("--scroll-duration",this.contentWidth/(60+10*this.speed)+"s")}cloning(){const t=parseInt(this.width/this.contentWidth)+1;for(let e=0;e<t;e++){let t=this.content.cloneNode(!0);t.classList.add("ticker__content--clone"),this.insertBefore(t,"right"===this.dataset.referral?this.content.previousSibling:this.content.nextSibling)}}}customElements.define("ticker-section",TickerSection);